const fs = require('fs');
const path = require('path');

const ASSETS_DIR = path.join(__dirname, '..', 'assets', 'xterm');
const OUTPUT = path.join(__dirname, '..', 'src', 'components', 'xterm-bundle.ts');

const xtermJs = fs.readFileSync(path.join(ASSETS_DIR, 'xterm.js'), 'utf8');
const xtermCss = fs.readFileSync(path.join(ASSETS_DIR, 'xterm.css'), 'utf8');
const fitJs = fs.readFileSync(path.join(ASSETS_DIR, 'addon-fit.js'), 'utf8');

const content = [
  '// Auto-generated by scripts/bundle-xterm.js — do not edit directly',
  '// To update: replace assets/xterm/*.js then run: node scripts/bundle-xterm.js',
  `export const XTERM_JS = ${JSON.stringify(xtermJs)};`,
  `export const XTERM_CSS = ${JSON.stringify(xtermCss)};`,
  `export const ADDON_FIT_JS = ${JSON.stringify(fitJs)};`,
].join('\n');

fs.writeFileSync(OUTPUT, content);

console.log(
  `Generated src/components/xterm-bundle.ts (${Math.round(xtermJs.length / 1024)}KB + ${Math.round(fitJs.length / 1024)}KB + ${Math.round(xtermCss.length / 1024)}KB)`,
);
